        public void OnUpdate(ref SystemState state)
        {
            var timeState = SystemAPI.GetSingleton<TimeState>();
            var tick = timeState.Tick;

            _residencyLookup.Update(ref state);
            _miracleRegistryLookup.Update(ref state);
