        private ComponentLookup<Space4XFleet> _fleetLookup;
        private ComponentLookup<Space4XLogisticsRoute> _logisticsRouteLookup;
        private ComponentLookup<Space4XAnomaly> _anomalyLookup;
        private ComponentLookup<LocalTransform> _transformLookup;

        public void OnCreate(ref SystemState state)
        {
            state.RequireForUpdate<RegistryDirectory>();
            state.RequireForUpdate<TimeState>();
            state.RequireForUpdate<RuntimeMiracleRegistry>();

            _colonyQuery = SystemAPI.QueryBuilder()
                .WithAll<Space4XColony, LocalTransform, SpatialIndexedTag>()
                .Build();

            _fleetQuery = SystemAPI.QueryBuilder()
